package com.careeros.watchlist.application; import com.careeros.watchlist.domain.*; import com.careeros.company.domain.*; import com.careeros.common.exception.ResourceNotFoundException; import org.springframework.data.domain.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.util.*;
@Service @Transactional public class WatchlistService{private final WatchlistRepository r;private final CompanyRepository companies;public WatchlistService(WatchlistRepository r,CompanyRepository c){this.r=r;companies=c;}public Watchlist create(String n){return r.save(Watchlist.create(n));}public Watchlist get(UUID id){return r.findById(id).orElseThrow(()->ResourceNotFoundException.forId("Watchlist",id));}public Page<Watchlist> list(Pageable p){return r.findAll(p);}public Watchlist rename(UUID id,String n){var w=get(id);w.rename(n);return r.save(w);}public Watchlist add(UUID id,UUID cid,int priority,boolean enabled){var w=get(id);var c=companies.findById(cid).orElseThrow(()->ResourceNotFoundException.forId("Company",cid));w.add(c,priority,enabled);return r.save(w);}public Watchlist remove(UUID id,UUID cid){var w=get(id);w.remove(cid);return r.save(w);}public void delete(UUID id){get(id);r.deleteById(id);}}
